const inbox = $('Claim Scheduling Reply Row').first()?.json;
const messageBody = (inbox?.payload?.messageBody ?? '').trim();
const slots = $('Fetch Offered Slots for Application').all().map(i => i.json);

const regexMatch = messageBody.match(/^\s*([123])\s*$/);
let slotIndex = null;
if (regexMatch) {
  slotIndex = parseInt(regexMatch[1], 10);
}

const ordinalMap = [
  ['second', 2], ['2nd', 2], ['two', 2],
  ['third', 3],  ['3rd', 3], ['three', 3],
  ['first', 1],  ['1st', 1], ['one', 1]
];
if (!slotIndex) {
  const lowerMsg = messageBody.toLowerCase();
  for (const [word, idx] of ordinalMap) {
    if (new RegExp('\\b' + word + '\\b').test(lowerMsg)) {
      slotIndex = idx;
      break;
    }
  }
}

return [{ json: {
  messageBody,
  slotIndex,
  regexMatched: slotIndex !== null,
  slots,
  candidateId: inbox?.candidate_id ?? '',
  applicationId: inbox?.application_id ?? '',
  inboxId: inbox?.id,
  repromptCount: inbox?.payload?.reprompt_count ?? 0
} }];

const haikusResponse = $json?.response ?? $json?.content ?? $json?.text ?? '{}';
let parsed = {};
try {
  const jsonMatch = haikusResponse.match(/\{[^}]+\}/);
  if (jsonMatch) parsed = JSON.parse(jsonMatch[0]);
} catch(e) {}

const parseNode = $('Parse Reply — Regex').first()?.json ?? {};

return [{ json: {
  ...parseNode,
  slotIndex: parsed.slot_index ?? null,
  regexMatched: parsed.slot_index != null
} }];

// Merge parse results from regex path or haiku path
const item = $json;
const slots = item.slots ?? [];
const slotIndex = item.slotIndex;

if (!slotIndex || slotIndex < 1 || slotIndex > slots.length) {
  return [{ json: { ...item, chosenSlot: null, chosenSlotId: null, valid: false } }];
}

const chosenSlot = slots[slotIndex - 1];
return [{ json: {
  ...item,
  chosenSlot,
  chosenSlotId: chosenSlot?.id ?? null,
  valid: !!chosenSlot
} }];

const claimedSlot = $('Atomic Claim Slot').first()?.json;
const interviewer = $('Fetch Interviewer for Interview').first()?.json;
const candidate = $('Fetch Candidate for Confirmation').first()?.json?.data?.candidate;

const startsAt = new Date(claimedSlot?.starts_at);
const dateStr = startsAt.toLocaleString('en-GH', {
  timeZone: 'Africa/Accra',
  weekday: 'long',
  month: 'long',
  day: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
});

// Check if calendar event was created (success path has calendarEventId)
let calendarNode = null;
try { calendarNode = $('Update Interview — Calendar Success').first()?.json; } catch(e) {}
const meetLink = $('Create Google Calendar Event').first()?.json?.htmlLink ?? null;

let message;
if (meetLink) {
  message = `Hi ${candidate?.firstName ?? 'there'},\n\nYour interview is confirmed!\n\nDate: ${dateStr}\nInterviewer: ${interviewer?.display_name ?? 'our team'}\nMeet link: ${meetLink}\n\nWe look forward to speaking with you.`;
} else {
  message = `Hi ${candidate?.firstName ?? 'there'},\n\nYour interview is confirmed!\n\nDate: ${dateStr}\nInterviewer: ${interviewer?.display_name ?? 'our team'}\n\nYour calendar invite will follow shortly.\n\nWe look forward to speaking with you.`;
}

return [{ json: {
  message,
  candidatePhone: candidate?.whatsappNumber ?? '',
  interviewerName: interviewer?.display_name ?? '',
  dateStr,
  meetLink: meetLink ?? null
} }];

// Filter out applications that already have offered/claimed slots
const allApps = $json?.data?.applications?.edges?.map(e => e.node) ?? [];

// Return each app as a separate item for splitInBatches
return allApps.map(app => ({ json: app }));

const slots = $('Fetch Next 3 Available Slots').all().map(i => i.json);
const app = $('Split Shortlisted Applications').first()?.json;
const candidateName = app?.candidate?.firstName ?? 'there';

const slotLines = slots.slice(0, 3).map((s, i) => {
  const dt = new Date(s.starts_at);
  const label = dt.toLocaleString('en-GH', {
    timeZone: 'Africa/Accra',
    weekday: 'long',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit'
  });
  return `${i+1}. ${label}`;
}).join('\n');

const message = `Hi ${candidateName},\n\nCongratulations! We would like to invite you for an interview. Please choose one of the following slots by replying with just the number (1, 2, or 3):\n\n${slotLines}\n\nThis offer is valid for 24 hours.`;

return [{ json: {
  message,
  candidatePhone: app?.candidate?.whatsappNumber ?? '',
  applicationId: app?.id ?? '',
  candidateId: app?.candidate?.id ?? ''
} }];

const avail = $json;
const dayOfWeek = avail.day_of_week; // 0=Sun
const [startH, startM] = avail.starts_local.split(':').map(Number);
const [endH, endM] = avail.ends_local.split(':').map(Number);
const slotMin = avail.slot_minutes ?? 45;

// Generate slots for next 14 days matching day_of_week
const slots = [];
const now = new Date();

for (let dayOffset = 0; dayOffset < 14; dayOffset++) {
  const date = new Date(now);
  date.setDate(date.getDate() + dayOffset);

  // Get day of week in Africa/Accra
  const accraDate = new Date(date.toLocaleString('en-US', { timeZone: 'Africa/Accra' }));
  if (accraDate.getDay() !== dayOfWeek) continue;

  // Generate slot start times within window
  let slotStart = new Date(accraDate);
  slotStart.setHours(startH, startM, 0, 0);

  const windowEnd = new Date(accraDate);
  windowEnd.setHours(endH, endM, 0, 0);

  while (slotStart.getTime() + slotMin * 60000 <= windowEnd.getTime()) {
    const slotEnd = new Date(slotStart.getTime() + slotMin * 60000);
    // Convert back to UTC ISO for storage
    slots.push({
      starts_at: slotStart.toISOString(),
      ends_at: slotEnd.toISOString()
    });
    slotStart = slotEnd;
  }
}

return [{ json: {
  ...avail,
  candidateSlots: slots
} }];

const avail = $('Compute Candidate Slot Times').first()?.json;
const freebusyData = $json;

const calId = avail.google_calendar_id;
const busyBlocks = freebusyData?.calendars?.[calId]?.busy ?? [];

const filteredSlots = (avail.candidateSlots ?? []).filter(slot => {
  const slotStart = new Date(slot.starts_at).getTime();
  const slotEnd = new Date(slot.ends_at).getTime();

  for (const busy of busyBlocks) {
    const busyStart = new Date(busy.start).getTime();
    const busyEnd = new Date(busy.end).getTime();
    // Overlap check: slot overlaps busy if not (slotEnd <= busyStart || slotStart >= busyEnd)
    if (!(slotEnd <= busyStart || slotStart >= busyEnd)) {
      return false; // Skip this slot
    }
  }
  return true;
});

return [{ json: {
  ...avail,
  filteredSlots,
  busyCount: busyBlocks.length,
  generatedCount: filteredSlots.length
} }];

// Build individual INSERT calls for each slot
// We use the Postgres node via a Code node that returns one item per slot
const avail = $json;
const slots = avail.filteredSlots ?? [];

if (slots.length === 0) {
  return [{ json: { inserted: 0, interviewerId: avail.interviewer_id } }];
}

// Return slots array for the next Postgres node to iterate
return slots.map(s => ({ json: {
  interviewer_id: avail.interviewer_id,
  starts_at: s.starts_at,
  ends_at: s.ends_at,
  slot_minutes: avail.slot_minutes
} }));

// Aggregate: count inserted items back to one per availability window
const items = $input.all();
const interviewerId = items[0]?.json?.interviewer_id ?? 'unknown';
return [{ json: {
  insertedCount: items.length,
  interviewer_id: interviewerId
} }];
